                    let inner = Rc::clone(&inner);
                    obj.insert(
                        "get".into(),
                        native(move |a| {
                            let key = a.first().unwrap_or(&JsValue::Undefined);
                            if let Some(id) = weak_collection_key(key) {
                                Ok(inner
                                    .borrow()
                                    .get(&id)
                                    .cloned()
                                    .unwrap_or(JsValue::Undefined))
                            } else {
                                Ok(JsValue::Undefined)
                            }
                        }),
                    );
