            if let JsValue::NativeFunction(f) = as_uint_n {
                // asUintN(8, 256n) = 0n
                let result = f(vec![JsValue::Smi(8), JsValue::BigInt(256)]).unwrap();
                assert_eq!(result, JsValue::BigInt(0));
            }
