    #[test]
    fn e2e_optional_computed_short_circuits_key_expression() {
        assert_eval_true("let hits = 0; let obj = null; obj?.[hits++]; hits === 0;");
    }

    #[test]
    fn e2e_optional_computed_reads_present_key() {
        assert_eq!(
            global_eval("let obj = { prop: 9 }; obj?.['prop']").unwrap(),
            JsValue::Smi(9)
        );
    }

