    fn e2e_array_every_short_circuit() {
        let r = global_eval(
            r#"
            var count = 0;
            [1, 2, 3, 4, 5].every(function(x) { count++; return x < 3; });
            count
            "#,
        )
        .unwrap();
        assert_eq!(r, JsValue::Smi(3));
    }

