        let result = global_eval(
            "var log = ''; function tag(n) { log = log + n; return n; } var value = ''; switch (3) { case tag(1): value = 'one'; break; default: value = 'default'; break; case tag(3): value = 'three'; break; } log + ':' + value",
        )
        .unwrap();
